      { icone: "🍗", titre: "Cuire le poulet", detail: "Dans une cocotte : poulet en morceaux + oignons émincés + safran + gingembre + cannelle + 1 cs ras el hanout + persil + coriandre + 1 verre d'eau + huile d'olive. Couvrir et cuire 45 min.", badge: "⏱ 45 min" },
      { icone: "✋", titre: "Effilocher", detail: "Sortir le poulet, désosser et effilocher à la main en filaments. Conserver le jus de cuisson.", badge: null },
      { icone: "🥚", titre: "Œufs brouillés", detail: "Faire réduire le jus de cuisson de moitié. Hors du feu, ajouter les œufs battus et remuer doucement à feu très doux jusqu'à crémeux (façon œufs brouillés). ASTUCE CHEF : on doit obtenir une crème dorée, pas des œufs durcis.", badge: "⏱ 8 min" },
      { icone: "🥜", titre: "Amandes caramélisées", detail: "Blanchir les amandes 2 min à l'eau bouillante, retirer la peau. Frire dans un peu d'huile jusqu'à dorées. Concasser grossièrement + 2 cs sucre + 1 cc cannelle. ASTUCE : cœur sucré-salé de la pastilla.", badge: "⏱ 10 min" },
      { icone: "📚", titre: "Mélanger garniture", detail: "Mélanger poulet effiloché + œufs brouillés. Goûter et ajuster (sel, ras el hanout). Doit être savoureux et bien parfumé.", badge: null },
      { icone: "🥧", titre: "Montage", detail: "Beurrer un moule rond (28cm). Disposer les feuilles de brick en étoile : moitié dans le moule, moitié qui dépasse. Badigeonner chaque feuille de beurre fondu. Mettre la moitié de la garniture poulet, couche d'amandes, reste de poulet.", badge: null },
      { icone: "✨", titre: "Refermer", detail: "Rabattre les feuilles qui dépassent par-dessus pour fermer. Ajouter 1-2 feuilles supplémentaires sur le dessus. Badigeonner abondamment de beurre fondu.", badge: null },
      { icone: "🔥", titre: "Cuire", detail: "Enfourner à 200°C 25-30 min jusqu'à BIEN dorée et croustillante. ASTUCE CHEF : retourner à mi-cuisson si possible pour dorer le dessous.", badge: "⏱ 30 min" },
      { icone: "🎨", titre: "Décor traditionnel", detail: "Saupoudrer généreusement de sucre glace. Décorer avec des lignes croisées de cannelle moulue (motif diagonal classique). Spectaculaire !", badge: null },
      { icone: "🍽️", titre: "Service", detail: "Servir CHAUD en entrée pour un repas de fête. Se mange à la main en parts. Le contraste croustillant/fondant/sucré/salé est inoubliable.", badge: null }
