      { nb: 15, pouletcuisses: "1.8 kg", rizbasmati: "1.2 kg", yaourt: "450 g", oignon: "750 g", epicesbiryani: "150 g", safran: "0 g", gingembreail: "150 g", menthe: "45 g" }
